<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#FFFFFF;">&#39;guarded_class&#39;:</span><span style="color:#ABB2BF;"> </span><span style="color:#FFFFFF;">&lt;weakref</span><span style="color:#ABB2BF;"> </span><span style="color:#FFFFFF;">at</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">0</span><span style="color:#FFFFFF;">x</span><span style="color:#D19A66;">7</span><span style="color:#FFFFFF;">f</span><span style="color:#D19A66;">8</span><span style="color:#FFFFFF;">f</span><span style="color:#D19A66;">98</span><span style="color:#FFFFFF;">cf</span><span style="color:#D19A66;">9440</span><span style="color:#FFFFFF;">;</span><span style="color:#ABB2BF;"> </span><span style="color:#FFFFFF;">to</span><span style="color:#ABB2BF;"> </span><span style="color:#FFFFFF;">&#39;torch._C._TensorMeta&#39;</span><span style="color:#ABB2BF;"> </span><span style="color:#FFFFFF;">at</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">0</span><span style="color:#FFFFFF;">x</span><span style="color:#D19A66;">57</span><span style="color:#FFFFFF;">f</span><span style="color:#D19A66;">3e10</span><span style="color:#ABB2BF;"> </span><span style="color:#FFFFFF;">(Tensor)&gt;</span></span>
